mapper.select:
select c.id, c.title, c.total_amount as totalAmount, us.real_name as initiatorName, c.occurred_date as occurredDate, c.due_time as dueTime, c.status, d.amount_due as myAmountDue, d.pay_status as myPayStatus from dm_shared_cost c left join user_student us on us.id = c.initiator_student_id and us.delflag = 0 left join dm_shared_cost_detail d on d.cost_id = c.id and d.student_id = #{query.studentId} and d.delflag = 0 where c.room_id = #{query.roomId} and c.delflag = 0
and( c.title like concat('%', #{query.keywords}, '%') or c.remark like concat('%', #{query.keywords}, '%'))
and c.status = #{query.state}
and date_format(c.occurred_date, '%Y-%m') = #{query.month}
and d.pay_status = 0 and c.status = 1
order by case c.status when 0 then 0 when 1 then 1 when 2 then 2 else 3 end, c.occurred_date desc, c.create_time desc

select count(1)
from room_student
where room_id = #{roomId}
  and student_id = #{studentId}
  and is_current = 1
